import{_ as e,c as r,l as t,a as o,t as l,a4 as s,o as i}from"./chunks/framework.CzsDe1xi.js";const T=JSON.parse('{"title":"C++ 命名空间","description":"","frontmatter":{"title":"C++ 命名空间"},"headers":[],"relativePath":"doc/编程语言/后端/Cplus/基础/类/命名空间.md","filePath":"packages/doc/src/编程语言/后端/Cplus/基础/类/命名空间.md","lastUpdated":1711551906000}'),n={name:"doc/编程语言/后端/Cplus/基础/类/命名空间.md"},c={id:"frontmatter-title",tabindex:"-1"},_=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=s('<p>命名空间是一种用来避免命名冲突的机制，它可以将一段代码的名称隔离开，使其与其他代码的名称不冲突。 命名空间的原理是将一个全局的作用域分成一个个命名空间，每个命名空间是个单独的作用域，同时若是在同一个作用域内可能出现的命名冲突也不会造成影响，有效避免了命名空间的污染；</p><h2 id="嵌套命名空间" tabindex="-1">嵌套命名空间 <a class="header-anchor" href="#嵌套命名空间" aria-label="Permalink to &quot;嵌套命名空间&quot;">​</a></h2><p>在一般情况下，命名空间还可以进行嵌套，即可以在一个命名空间内嵌再嵌套命名空间,以此类推。</p><p>在一般情况下，若是想使用命名空间内的成员，可以使用作用域限定符 ::(域解析操作符)</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>命名空间可以避免命名冲突问题；</p><ul><li>命名空间可以进行嵌套；</li><li>命名空间必须在全局范围内定义，不可再局部范围内定义；</li><li>在使用命名空间内的成员时共有三种方法(作用域限定符、命名空间全部展开、命名空间部分展开)，在一般练习中尽量不要进行全部展开；</li></ul>',7);function p(a,h,m,f,u,C){return i(),r("div",null,[t("h1",c,[o(l(a.$frontmatter.title)+" ",1),_]),d])}const b=e(n,[["render",p]]);export{T as __pageData,b as default};
